-- =====================================================
-- California (CA) Medical Malpractice Rules
-- Enhanced Verification Protocol v2.0
-- =====================================================
-- State: California
-- Governing Law: MICRA (Medical Injury Compensation Reform Act), CCP § 340.5, Civ. Code § 3333.2
-- Negligence Model: PURE COMPARATIVE FAULT (Li v. Yellow Cab Co., 13 Cal.3d 804 (1975))
-- SOL: 3 years from injury OR 1 year from discovery — whichever is EARLIER (CCP § 340.5)
-- Non-Economic Cap: $350,000 (AB 35, effective Jan 1 2023); rising $40K/yr to $750K by 2033
-- Wrongful Death Cap: $500,000 (rising $50K/yr to $1M by 2033)
-- Pre-suit Notice: 90 days written notice to defendant required (CCP § 364)
-- Attorney Fees: Sliding scale limitation (Civ. Code § 6146)
-- =====================================================

-- RULE 1: STANDARD OF CARE
INSERT INTO leverage.validation_rules (rule_name, validator_level, validator_name, validator_type, practice_area, specialization, document_type, jurisdiction_scope, jurisdiction_state, validator_config, severity, review_status, is_active, is_template, created_at, updated_at)
VALUES ('CA-MED-MAL-STANDARD-OF-CARE', 5, 'CA Medical Malpractice: Standard of Care (MICRA / Common Law)', 'content_check', 'personal_injury', 'medical_malpractice', 'complaint', 'state', 'CA',
    jsonb_build_object('sub_specialization_type', 'medical_malpractice', 'authority_level', 'contextual_rule', 'standard_text', 'A healthcare provider must use the degree of skill, knowledge, and care ordinarily possessed and exercised by members of the profession in good standing in the same or similar locality', 'key_elements', jsonb_build_array('Duty: provider-patient relationship established', 'Breach: failure to meet the standard of care', 'Causation: breach was a substantial factor in causing the injury', 'Damages: actual harm resulted'), 'locality_rule', 'California applies a modified locality rule — standard of care for general practitioners is measured in same or similar locality; specialists are held to a national standard', 'res_ipsa', 'Available under specific circumstances where injury would not ordinarily occur without negligence and the instrumentality was in defendant control (CACI 513)', 'informed_consent', 'Separate claim under Cobbs v. Grant, 8 Cal.3d 229 (1972); provider must disclose risks a reasonable patient would want to know — objective reasonable patient standard', 'hospital_liability', 'Hospitals liable for non-delegable duties and under ostensible agency for physicians without clear disclosure of independent contractor status', 'verification', jsonb_build_object('statute_verified', true, 'sources', jsonb_build_array('MICRA — California Medical Injury Compensation Reform Act', 'CACI 500 et seq.', 'Cobbs v. Grant, 8 Cal.3d 229 (1972)', 'Justia — California Medical Malpractice'), 'confidence', 'high')),
    'error', 'document_verified', true, false, NOW(), NOW())
ON CONFLICT (rule_name) DO UPDATE SET validator_config = EXCLUDED.validator_config, updated_at = NOW();

-- RULE 2: EXPERT WITNESS AND PRE-SUIT NOTICE
INSERT INTO leverage.validation_rules (rule_name, validator_level, validator_name, validator_type, practice_area, specialization, document_type, jurisdiction_scope, jurisdiction_state, validator_config, severity, review_status, is_active, is_template, created_at, updated_at)
VALUES ('CA-MED-MAL-PRE-SUIT-NOTICE', 5, 'CA Medical Malpractice: 90-Day Pre-Suit Notice Required (CCP § 364)', 'content_check', 'personal_injury', 'medical_malpractice', 'complaint', 'state', 'CA',
    jsonb_build_object('sub_specialization_type', 'medical_malpractice', 'authority_level', 'contextual_rule', 'statute', 'CCP § 364', 'requirement', 'MANDATORY — Plaintiff must provide at least 90 days written notice to the defendant healthcare provider BEFORE filing a medical malpractice lawsuit', 'notice_contents', jsonb_build_object('who', 'Must be provided to each defendant healthcare provider named in the intended suit', 'what', 'Written notice specifying: the legal basis for the claim, the type of loss incurred, and the nature of the injuries suffered'), 'sol_tolling', 'If notice is given within 90 days of the SOL deadline, the SOL is extended by 90 days from the date of notice', 'failure_to_give_notice', 'Failure to give proper notice does not deprive court of jurisdiction but gives defendant ground to challenge', 'expert_requirement', 'Expert testimony required at trial to prove standard of care and breach; no statutory pre-filing affidavit required in California', 'expert_qualifications', 'Expert must be licensed healthcare provider in same or related specialty; must be familiar with standard of care applicable at time and in relevant locality', 'attorney_fees', jsonb_build_object('statute', 'Civ. Code § 6146', 'rule', 'Attorney fees in medical malpractice cases are limited to a sliding scale: 40% of first $50K, 33.3% of next $50K, 25% of next $500K, 15% of amounts over $600K'), 'verification', jsonb_build_object('statute_verified', true, 'sources', jsonb_build_array('CCP § 364', 'Civ. Code § 6146', 'California Legislature', 'Justia — California CCP § 364'), 'confidence', 'high')),
