-- RULE 3: MICRA DAMAGE CAPS
INSERT INTO leverage.validation_rules (rule_name, validator_level, validator_name, validator_type, practice_area, specialization, document_type, jurisdiction_scope, jurisdiction_state, validator_config, severity, review_status, is_active, is_template, created_at, updated_at)
VALUES ('CA-MED-MAL-MICRA-DAMAGE-CAPS', 5, 'CA Medical Malpractice: MICRA Non-Economic Cap $350K (Civ. Code § 3333.2, AB 35)', 'content_check', 'personal_injury', 'medical_malpractice', 'complaint', 'state', 'CA',
    jsonb_build_object('sub_specialization_type', 'medical_malpractice', 'authority_level', 'contextual_rule', 'statute', 'Civ. Code § 3333.2 (MICRA)', 'economic_damages', 'UNCAPPED — full recovery of all economic losses (medical expenses, lost earnings, future care, rehabilitation)', 'non_economic_damages', jsonb_build_object('original_cap', '$250,000 (1975–2022)', 'current_cap_2023', '$350,000 — effective January 1, 2023 (AB 35)', 'annual_increases', 'Cap increases $40,000/year until reaching $750,000 in 2033, then indexed to inflation', 'cap_schedule', jsonb_build_object('2023', '$350,000', '2024', '$390,000', '2025', '$430,000', '2026', '$470,000', '2033_and_beyond', '$750,000 then CPI-indexed'), 'applies_to', 'Pain and suffering, mental anguish, loss of consortium, disfigurement, loss of enjoyment of life'), 'wrongful_death', jsonb_build_object('cap_2023', '$500,000', 'annual_increases', 'Cap increases $50,000/year until reaching $1,000,000 in 2033, then inflation-indexed', 'cap_2026', '$650,000'), 'cap_per_case', 'Cap applies per plaintiff regardless of number of defendant providers', 'punitive_damages', jsonb_build_object('availability', 'Limited under MICRA — must show clear and convincing evidence of oppression, fraud, or malice', 'not_subject_to_micra_cap', 'Punitive damages are NOT subject to the non-economic damage cap'), 'collateral_source', 'California allows defendants to present evidence of collateral source payments to reduce economic damage awards (Civ. Code § 3333.1)', 'verification', jsonb_build_object('statute_verified', true, 'sources', jsonb_build_array('Civ. Code § 3333.2', 'AB 35 (2022)', 'Civ. Code § 3333.1', 'California Legislature', 'Justia — California MICRA'), 'confidence', 'high')),
