-- RULE 4: STATUTE OF LIMITATIONS
INSERT INTO leverage.validation_rules (rule_name, validator_level, validator_name, validator_type, practice_area, specialization, document_type, jurisdiction_scope, jurisdiction_state, validator_config, severity, review_status, is_active, is_template, created_at, updated_at)
VALUES ('CA-MED-MAL-SOL-3-YEARS', 5, 'CA Medical Malpractice: 3-Year/1-Year SOL — Whichever Earlier (CCP § 340.5)', 'content_check', 'personal_injury', 'medical_malpractice', 'complaint', 'state', 'CA',
    jsonb_build_object('sub_specialization_type', 'medical_malpractice', 'authority_level', 'contextual_rule', 'statute', 'CCP § 340.5', 'sol_rule', 'EARLIER of: (1) 3 years from the date of injury, OR (2) 1 year from the date the plaintiff discovered or should have discovered the injury', 'statute_text', 'CCP § 340.5: An action for injury or death against a health care provider shall be commenced within three years after the date of injury or one year after the plaintiff discovers, or through the use of reasonable diligence should have discovered, the injury, whichever occurs first', 'three_year_rule', 'Outer limit: 3 years from actual injury date regardless of discovery — this is the statute of repose', 'one_year_discovery', 'Inner limit: 1 year from date plaintiff actually discovered (or reasonably should have discovered) the injury AND its negligent cause', 'which_governs', 'File whichever deadline expires FIRST — most plaintiffs face the 1-year discovery rule as the tighter deadline', 'fraud_exception', 'SOL tolled where defendant fraudulently concealed the malpractice; clock does not start until concealment is discovered', 'foreign_object', 'Foreign object left in body: 1 year from discovery of foreign object (within 3-year outer limit)', 'minors', 'For minors: SOL is 3 years OR until 8th birthday, whichever is LONGER', 'pre_suit_notice_effect', 'Providing 90-day CCP § 364 pre-suit notice within 90 days before SOL expiration extends the SOL by 90 days from date of notice', 'tolling', jsonb_build_array('Fraudulent concealment', 'Minority (extended to age 8 or 3 years from injury)', 'Continuous treatment (some circumstances)', 'CCP § 364 pre-suit notice (tolls by 90 days)'), 'practical_examples', jsonb_build_array('Surgery Jan 1 2024, discovered negligence Mar 1 2024 → File by Mar 1 2025 (1-yr discovery)', 'Surgery Jan 1 2024, never specifically discovered → File by Jan 1 2027 (3-yr outer limit)'), 'verification', jsonb_build_object('statute_verified', true, 'sources', jsonb_build_array('CCP § 340.5', 'California Legislature', 'Fogarty v. Superior Court, 117 Cal.App.3d 316 (1981)', 'Justia — CCP 340.5'), 'confidence', 'high')),
    'error', 'document_verified', true, false, NOW(), NOW())
ON CONFLICT (rule_name) DO UPDATE SET validator_config = EXCLUDED.validator_config, updated_at = NOW();

-- RULE 5: PURE COMPARATIVE FAULT
INSERT INTO leverage.validation_rules (rule_name, validator_level, validator_name, validator_type, practice_area, specialization, document_type, jurisdiction_scope, jurisdiction_state, validator_config, severity, review_status, is_active, is_template, created_at, updated_at)
VALUES ('CA-MED-MAL-PURE-COMPARATIVE-FAULT', 5, 'CA Medical Malpractice: Pure Comparative Fault (Li v. Yellow Cab / CCP § 1431.2)', 'content_check', 'personal_injury', 'medical_malpractice', 'complaint', 'state', 'CA',
    jsonb_build_object('sub_specialization_type', 'medical_malpractice', 'authority_level', 'contextual_rule', 'case_law', 'Li v. Yellow Cab Co., 13 Cal.3d 804 (1975)', 'statute', 'CCP § 1431.2 (several liability for non-economic damages)', 'negligence_model', 'pure_comparative_fault', 'rule', 'Plaintiff can recover even if 99% at fault; damages reduced proportionally by plaintiff fault percentage', 'patient_contributory_conduct', 'Patient failure to follow medical orders, delayed seeking care, or failure to disclose relevant history reduces recovery proportionally', 'economic_damages_liability', 'Each defendant jointly and severally liable for all economic damages (medical bills, lost wages)', 'non_economic_damages_liability', 'Each defendant SEVERALLY LIABLE ONLY for non-economic damages — pays only their proportionate share (CCP § 1431.2)', 'practical_examples', jsonb_build_array('Plaintiff 0% at fault: Full recovery of all damages', 'Plaintiff 20% at fault: Economic damages fully recoverable from any defendant; non-economic reduced by 20%', 'Plaintiff 99% at fault: Can still recover 1% of damages'), 'multiple_defendants', 'Joint and several for economic damages; several only for non-economic damages per Proposition 51 (1986)', 'verification', jsonb_build_object('statute_verified', true, 'sources', jsonb_build_array('Li v. Yellow Cab Co., 13 Cal.3d 804 (1975)', 'CCP § 1431.2', 'California Proposition 51 (1986)', 'California Legislature'), 'confidence', 'high')),
    'error', 'document_verified', true, false, NOW(), NOW())
